use std::collections::{BTreeSet, HashMap};
use std::fmt;
use std::io;

use crate::report::{CaseReport, ReportItem};

/// Native Rust translation of the attached `path-discovery.n3` example.
///
/// Unlike the RDF/N3 original, this version uses plain Rust data:
/// - airport ids plus display labels
/// - direct `(from, to)` flight edges
/// - an adjacency map for traversal
/// - a depth-limited DFS for route discovery
///
/// The dataset is the full airport/route graph from the original N3 file.
/// The query remains the same: find all simple routes from
/// Ostend-Bruges International Airport to Václav Havel Airport Prague
/// with at most 2 stopovers.
#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash, PartialOrd, Ord)]
struct AirportId(u16);

impl fmt::Display for AirportId {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        f.write_str(label_for(*self).unwrap_or("<unknown airport>"))
    }
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
struct Flight {
    from: AirportId,
    to: AirportId,
}

#[derive(Debug, Clone)]
struct RouteQuery {
    source: AirportId,
    destination: AirportId,
    max_stopovers: usize,
}

#[derive(Debug, Clone, PartialEq, Eq, PartialOrd, Ord)]
struct Route {
    airports: Vec<AirportId>,
}

impl Route {
    fn stopovers(&self) -> usize {
        self.airports.len().saturating_sub(2)
    }
}

pub fn report() -> io::Result<CaseReport> {
    let query = RouteQuery {
        source: airport_id("Ostend-Bruges International Airport")?,
        destination: airport_id("Václav Havel Airport Prague")?,
        max_stopovers: 2,
    };

    let flights = flights();
    let graph = adjacency(&flights);
    let routes = discover_routes(&query, &graph);
    let routes_respect_stopovers = routes
        .iter()
        .all(|route| route.stopovers() <= query.max_stopovers);
    let routes_are_simple = routes.iter().all(route_is_simple);
    let routes_match_query = routes.iter().all(|route| {
        route.airports.first().copied() == Some(query.source)
            && route.airports.last().copied() == Some(query.destination)
    });
    let exact_route_set_matches = routes == expected_original_routes()?;

    if routes.is_empty()
        || !routes_respect_stopovers
        || !routes_are_simple
        || !routes_match_query
        || !exact_route_set_matches
    {
        return Err(io::Error::new(
            io::ErrorKind::InvalidData,
            "path-discovery check failed: a stopover, simplicity, endpoint, or known-answer check failed",
        ));
    }

    let mut reason = vec![
        ReportItem::text(
            "The airport graph is built from the full source dataset, then a depth-limited DFS enumerates simple paths that respect the stopover limit.",
        ),
        ReportItem::field("airports", data::AIRPORTS.len().to_string()),
        ReportItem::field("flights", flights.len().to_string()),
        ReportItem::field("source", query.source.to_string()),
        ReportItem::field("destination", query.destination.to_string()),
        ReportItem::field("max stopovers", query.max_stopovers.to_string()),
    ];
    for (index, route) in routes.iter().enumerate() {
        reason.push(ReportItem::text(format!("Route #{}", index + 1)));
        reason.push(ReportItem::field("Stopovers", route.stopovers().to_string()));
        reason.push(ReportItem::field("Airports", route_airports_string(route)));
    }

    Ok(CaseReport::new("path-discovery")
        .with_answer(vec![
            ReportItem::text(
                "The path-discovery case finds every simple route from Ostend-Bruges International Airport to Václav Havel Airport Prague with at most two stopovers.",
            ),
            ReportItem::field("case", "path-discovery"),
            ReportItem::field("routes found", routes.len().to_string()),
        ])
        .with_reason_why(reason)
        .with_check(vec![
            ReportItem::field(
                "all routes within stopover bound",
                if routes_respect_stopovers { "yes" } else { "no" },
            ),
            ReportItem::field(
                "all routes are simple paths",
                if routes_are_simple { "yes" } else { "no" },
            ),
            ReportItem::field(
                "all routes match endpoints",
                if routes_match_query { "yes" } else { "no" },
            ),
            ReportItem::field(
                "route set matches known answer",
                if exact_route_set_matches { "yes" } else { "no" },
            ),
        ]))
}

pub fn run_and_print() -> io::Result<()> {
    let query = RouteQuery {
        source: airport_id("Ostend-Bruges International Airport")?,
        destination: airport_id("Václav Havel Airport Prague")?,
        max_stopovers: 2,
    };

    let flights = flights();
    let graph = adjacency(&flights);
    let routes = discover_routes(&query, &graph);
    let routes_respect_stopovers = routes
        .iter()
        .all(|route| route.stopovers() <= query.max_stopovers);
    let routes_are_simple = routes.iter().all(route_is_simple);
    let routes_match_query = routes.iter().all(|route| {
        route.airports.first().copied() == Some(query.source)
            && route.airports.last().copied() == Some(query.destination)
    });
    let exact_route_set_matches = routes == expected_original_routes()?;

    println!("=== Answer ===");
    println!(
        "The path-discovery case finds every simple route from Ostend-Bruges International Airport to Václav Havel Airport Prague with at most two stopovers."
    );
    println!("case          : path-discovery");
    println!("routes found  : {}", routes.len());
    println!();
    println!("=== Reason Why ===");
    println!(
        "The airport graph is built from the full source dataset, then a depth-limited DFS enumerates simple paths that respect the stopover limit."
    );
    println!("airports      : {}", data::AIRPORTS.len());
    println!("flights       : {}", flights.len());
    println!("source        : {}", query.source);
    println!("destination   : {}", query.destination);
    println!("max stopovers : {}", query.max_stopovers);

    for (index, route) in routes.iter().enumerate() {
        println!();
        println!("Route #{}", index + 1);
        println!(" Stopovers    : {}", route.stopovers());
        println!(
            " Airports     : {}",
            route_airports_string(route)
        );
    }

    println!();
    println!("=== Check ===");
    println!(
        "all routes within stopover bound : {}",
        if routes_respect_stopovers { "yes" } else { "no" }
    );
    println!(
        "all routes are simple paths      : {}",
        if routes_are_simple { "yes" } else { "no" }
    );
    println!(
        "all routes match endpoints       : {}",
        if routes_match_query { "yes" } else { "no" }
    );
    println!(
        "route set matches known answer   : {}",
        if exact_route_set_matches { "yes" } else { "no" }
    );

    if routes.is_empty()
        || !routes_respect_stopovers
        || !routes_are_simple
        || !routes_match_query
        || !exact_route_set_matches
    {
        return Err(io::Error::new(
            io::ErrorKind::InvalidData,
            "path-discovery check failed: a stopover, simplicity, endpoint, or known-answer check failed",
        ));
    }

    Ok(())
}

fn airport_id(label: &str) -> io::Result<AirportId> {
    data::AIRPORTS
        .iter()
        .find_map(|(id, candidate)| (*candidate == label).then_some(AirportId(*id)))
        .ok_or_else(|| io::Error::new(io::ErrorKind::NotFound, format!("airport not found: {label}")))
}

fn label_for(airport: AirportId) -> Option<&'static str> {
    data::AIRPORTS
        .binary_search_by_key(&airport.0, |(id, _)| *id)
        .ok()
        .map(|index| data::AIRPORTS[index].1)
}

fn flights() -> Vec<Flight> {
    data::FLIGHTS
        .iter()
        .map(|(from, to)| Flight {
            from: AirportId(*from),
            to: AirportId(*to),
        })
        .collect()
}

fn adjacency(flights: &[Flight]) -> HashMap<AirportId, Vec<AirportId>> {
    let mut graph: HashMap<AirportId, Vec<AirportId>> = HashMap::new();

    for flight in flights {
        graph.entry(flight.from).or_default().push(flight.to);
    }

    graph
}

fn discover_routes(query: &RouteQuery, graph: &HashMap<AirportId, Vec<AirportId>>) -> Vec<Route> {
    let max_legs = query.max_stopovers + 1;
    let mut visited = BTreeSet::new();
    let mut current = vec![query.source];
    let mut routes = Vec::new();

    visited.insert(query.source);

    dfs(
        query.source,
        query.destination,
        max_legs,
        graph,
        &mut visited,
        &mut current,
        &mut routes,
    );

    routes.sort();
    routes
}

fn route_airports_string(route: &Route) -> String {
    route.airports
        .iter()
        .map(|airport| label_for(*airport).unwrap_or("<unknown airport>"))
        .collect::<Vec<_>>()
        .join(" -> ")
}

fn route_is_simple(route: &Route) -> bool {
    let unique: BTreeSet<_> = route.airports.iter().copied().collect();
    unique.len() == route.airports.len()
}

fn expected_original_routes() -> io::Result<Vec<Route>> {
    let mut routes = vec![
        Route {
            airports: vec![
                airport_id("Ostend-Bruges International Airport")?,
                airport_id("Liège Airport")?,
                airport_id("Heraklion International Nikos Kazantzakis Airport")?,
                airport_id("Václav Havel Airport Prague")?,
            ],
        },
        Route {
            airports: vec![
                airport_id("Ostend-Bruges International Airport")?,
                airport_id("Liège Airport")?,
                airport_id("Diagoras Airport")?,
                airport_id("Václav Havel Airport Prague")?,
            ],
        },
        Route {
            airports: vec![
                airport_id("Ostend-Bruges International Airport")?,
                airport_id("Liège Airport")?,
                airport_id("Palma De Mallorca Airport")?,
                airport_id("Václav Havel Airport Prague")?,
            ],
        },
    ];
    routes.sort();
    Ok(routes)
}

fn dfs(
    current_airport: AirportId,
    destination: AirportId,
    max_legs: usize,
    graph: &HashMap<AirportId, Vec<AirportId>>,
    visited: &mut BTreeSet<AirportId>,
    current_route: &mut Vec<AirportId>,
    routes: &mut Vec<Route>,
) {
    if current_airport == destination {
        routes.push(Route {
            airports: current_route.clone(),
        });
        return;
    }

    let legs_so_far = current_route.len().saturating_sub(1);
    if legs_so_far == max_legs {
        return;
    }

    let Some(outbound) = graph.get(&current_airport) else {
        return;
    };

    for &next in outbound {
        if visited.contains(&next) {
            continue;
        }

        visited.insert(next);
        current_route.push(next);
        dfs(
            next,
            destination,
            max_legs,
            graph,
            visited,
            current_route,
            routes,
        );
        current_route.pop();
        visited.remove(&next);
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    fn original_query(max_stopovers: usize) -> RouteQuery {
        RouteQuery {
            source: airport_id("Ostend-Bruges International Airport").unwrap(),
            destination: airport_id("Václav Havel Airport Prague").unwrap(),
            max_stopovers,
        }
    }

    fn original_query_routes(max_stopovers: usize) -> Vec<Route> {
        let graph = adjacency(&flights());
        discover_routes(&original_query(max_stopovers), &graph)
    }

    #[test]
    fn keeps_the_full_graph_from_the_attached_n3_input() {
        assert_eq!(data::AIRPORTS.len(), 7_698);
        assert_eq!(data::FLIGHTS.len(), 37_274);
    }

    #[test]
    fn airport_lookup_and_display_round_trip_for_known_airports() {
        let ostend = airport_id("Ostend-Bruges International Airport").unwrap();
        let prague = airport_id("Václav Havel Airport Prague").unwrap();

        assert_eq!(label_for(ostend), Some("Ostend-Bruges International Airport"));
        assert_eq!(label_for(prague), Some("Václav Havel Airport Prague"));
        assert_eq!(ostend.to_string(), "Ostend-Bruges International Airport");
        assert_eq!(prague.to_string(), "Václav Havel Airport Prague");
    }

    #[test]
    fn adjacency_contains_the_known_ostend_to_liege_flight() {
        let graph = adjacency(&flights());
        let ostend = airport_id("Ostend-Bruges International Airport").unwrap();
        let liege = airport_id("Liège Airport").unwrap();

        let outbound = graph
            .get(&ostend)
            .expect("Ostend should have outbound flights in the dataset");

        assert_eq!(outbound, &vec![liege]);
    }

    #[test]
    fn stopover_limit_changes_the_number_of_discovered_routes() {
        assert!(original_query_routes(0).is_empty());
        assert!(original_query_routes(1).is_empty());
        assert_eq!(original_query_routes(2).len(), 3);
        assert_eq!(original_query_routes(3).len(), 152);
    }

    #[test]
    fn discovered_routes_are_simple_paths_without_repeated_airports() {
        for route in original_query_routes(3) {
            let unique: BTreeSet<_> = route.airports.iter().copied().collect();
            assert_eq!(unique.len(), route.airports.len(), "route should not repeat airports");
        }
    }

    #[test]
    fn finds_the_three_routes_from_the_original_query() {
        let actual = original_query_routes(2);

        let expected = vec![
            Route {
                airports: vec![
                    airport_id("Ostend-Bruges International Airport").unwrap(),
                    airport_id("Liège Airport").unwrap(),
                    airport_id("Heraklion International Nikos Kazantzakis Airport").unwrap(),
                    airport_id("Václav Havel Airport Prague").unwrap(),
                ],
            },
            Route {
                airports: vec![
                    airport_id("Ostend-Bruges International Airport").unwrap(),
                    airport_id("Liège Airport").unwrap(),
                    airport_id("Diagoras Airport").unwrap(),
                    airport_id("Václav Havel Airport Prague").unwrap(),
                ],
            },
            Route {
                airports: vec![
                    airport_id("Ostend-Bruges International Airport").unwrap(),
                    airport_id("Liège Airport").unwrap(),
                    airport_id("Palma De Mallorca Airport").unwrap(),
                    airport_id("Václav Havel Airport Prague").unwrap(),
                ],
            },
        ];

        assert_eq!(actual, expected);
    }
}

